import{_ as l,r as o,o as r,c as d,a as e,b as t,d as i,w as u,e as n}from"./app-d1e08aba.js";const c={},h=n('<h1 id="getting-started" tabindex="-1"><a class="header-anchor" href="#getting-started" aria-hidden="true">#</a> Getting Started</h1><p>Ultimate Member plugin providees many features &amp; functionalities as a base for developing Membership &amp; Communitiy sites with WordPress. It has a lot of available Filter &amp; Action hooks to help extend and customize the plugin depending on the type of membership sites that you are developing.</p><p>There are many approaches in building membership/community sites with Ultimate Member but there&#39;s a limitation: not all features &amp; functionalities are implemented as the base only includes the most popularly known &amp; used features/functionalities. With the help of this Extended plugin, it compiles all those missing basic features &amp; functionalities contributed &amp; shared by many of our community developers so you may use them freely.</p><table><thead><tr><th>Core</th><th style="text-align:center;">Latest</th><th style="text-align:center;">Pre-Release</th></tr></thead><tbody><tr><td><img src="https://img.shields.io/badge/Requires-version_2.6.8+-7856ff" alt="Static Badge"></td><td style="text-align:center;"><img src="https://img.shields.io/github/v/release/ultimatemember/Extended?label=Latest Release" alt="GitHub release (with filter)"></td><td style="text-align:center;"><img src="https://img.shields.io/github/v/release/ultimatemember/Extended?filter=2.0.1-alpha2&amp;label=Version" alt="GitHub release (with filter)"></td></tr></tbody></table>',4),p={class:"custom-container tip"},m=e("p",{class:"custom-container-title"},"How To Contribute?",-1),g=e("a",{href:"./how-to-contribute"},"Contribute",-1),f=e("hr",null,null,-1),b=e("hr",null,null,-1),y=e("h1",{id:"installation",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#installation","aria-hidden":"true"},"#"),t(" Installation")],-1),x=e("p",null,"This article serves as a guide for installing the basic extension, offering step-by-step instructions to ensure a smooth installation process.",-1),_={href:"https://github.com/ultimatemember/Extended/releases",target:"_blank",rel:"noopener noreferrer"},w=n('<li>Extract the zip file to your local computer.</li><li>There are two ways to use the extended plugin: <ul><li><strong>Individual extensions:</strong> You can use individual extensions or plugins in the /Extended/src/ directory, and upload them to your site. <ul><li>For example, If you only need the Browser Detect plugin: <ul><li>Click on the <strong>Individual-Extensions.zip</strong> to download the extensions. <img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65578310faa0932173ab7952/file-aPSJLfrflX.png" alt=""></li><li>After downloading, extract the file. The resulting extraction forms a folder named &quot;<strong>assets</strong>,&quot; containing separate zip files for each basic extension.<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/6557833d02a73d2b897aef6d/file-Bd0a9V8Lwt.png" alt=""></li><li>Upload it to your site by selecting only the um-browser-detect zip and once the plugin is uploaded and activated, it will automatically enable all features &amp; functionalities related to the plugin/extension.</li></ul></li></ul></li><li><strong>Whole Extended plugin:</strong> Upload the whole Extended plugin zip file to your site and enable each extension on the Extended settings. <ul><li>Once you activate the plugin, it will add the &quot;<strong>UM Extended&quot;</strong> tab to the WP Side navigation menu.</li><li>Clicking the &quot;UM Extended&quot; tab will display all the Ultimate Member Basic Extensions. You have the option to enable and activate all the extensions by clicking the <strong>&quot;Enable All Active&quot;</strong> toggle switch button.</li><li><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/654a59959c4ad7036dd6f7d5/file-70RCfGeY7t.png" alt=""> If you only require a specific basic extension, click the name of your preferred basic extension. It will take you to its activation page, where you can click the <strong>&quot;Activate&quot;</strong> button.<br><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/654a5a6777469859d4f1c063/file-UgKSSpr12O.png" alt=""></li></ul></li></ul></li>',2),v=e("h2",{id:"updating-plugins",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#updating-plugins","aria-hidden":"true"},"#"),t(" Updating Plugins")],-1),E={href:"https://github.com/ultimatemember/Extended/releases",target:"_blank",rel:"noopener noreferrer"},k=e("code",null,'"Watch"',-1);function q(z,C){const s=o("RouterLink"),a=o("ExternalLinkIcon");return r(),d("div",null,[h,e("div",p,[m,e("p",null,[t("Do you want to share ideas & customizations to help others? Please read our guide on how to "),g,t(". Are you a Developer? Please see our guide to "),i(s,{to:"/create-extensions/"},{default:u(()=>[t("develop extensions")]),_:1}),t(".")])]),f,b,y,x,e("ol",null,[e("li",null,[t("Download the latest version of the Extended plugin from this "),e("a",_,[t("GitHub repository"),i(a)])]),w]),v,e("p",null,[t("To update the plugin, you must download the latest release from the "),e("a",E,[t("Github repository"),i(a)]),t(" and override the plugins manually via SFTP/FTP client. We recommend that you subscribe to the Github repository by clicking on the "),k,t(" button to notify you with the plugin updates & developer activities.")])])}const P=l(c,[["render",q],["__file","installation.html.vue"]]);export{P as default};
